export const FONT_LINKS = "<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Syne:wght@600;700&family=Nunito+Sans:opsz,wght@6..12,400;6..12,600;6..12,700&family=DM+Mono:wght@400;500&display=swap\" rel=\"stylesheet\">";

export const STYLE_BLOCK = "<style>\n/* ============================================================\n   TEMPLATE DE APRESENTAÇÕES — GRUPO YBERA\n   Arquivo de referência para o Claude reproduzir.\n   Slides: 1920×1080. Tema via data-marca / data-tom no <body>.\n   ============================================================ */\n\n/* ---------- TOKENS DE MODO (fundo e tinta) ----------\n   Atributos data-marca / data-tom ficam no <body> (nomes próprios,\n   para não conflitar com data-theme que o navegador/host pode usar). */\nbody[data-tom=\"dark\"] {\n  --bg: rgb(5,5,5);\n  --ink: rgb(250,249,252);\n  --ink2: rgb(224,223,226);\n  --ink3: rgb(176,175,178);\n  --hairline: rgba(250,249,252,0.06);\n  --line18: rgba(250,249,252,0.18);\n  --line25: rgba(250,249,252,0.25);\n  --line35: rgba(250,249,252,0.35);\n}\nbody[data-tom=\"light\"] {\n  --bg: rgb(250,249,252);\n  --ink: rgb(5,5,5);\n  --ink2: rgb(48,48,50);\n  --ink3: rgb(108,107,110);\n  --hairline: rgba(5,5,5,0.07);\n  --line18: rgba(5,5,5,0.2);\n  --line25: rgba(5,5,5,0.28);\n  --line35: rgba(5,5,5,0.38);\n}\n\n/* ---------- TOKENS DE TEMA (marca) ---------- */\nbody[data-marca=\"group\"][data-tom=\"dark\"]  { --accent: rgb(201,200,204); --accent-border: rgb(108,107,110); --sep-bg: rgb(226,225,229); --sep-text: rgb(5,5,5); }\nbody[data-marca=\"group\"][data-tom=\"light\"] { --accent: rgb(90,89,92);    --accent-border: rgb(176,175,178); --sep-bg: rgb(30,30,31);    --sep-text: rgb(250,249,252); }\nbody[data-marca=\"ybera\"][data-tom=\"dark\"]  { --accent: rgb(176,175,178); --accent-border: rgb(108,107,110); --sep-bg: rgb(236,235,240); --sep-text: rgb(5,5,5); }\nbody[data-marca=\"ybera\"][data-tom=\"light\"] { --accent: rgb(108,107,110); --accent-border: rgb(176,175,178); --sep-bg: rgb(30,30,31);    --sep-text: rgb(250,249,252); }\nbody[data-marca=\"club\"][data-tom=\"dark\"]   { --accent: rgb(199,15,67);   --accent-border: rgb(152,11,56);   --sep-bg: rgb(199,15,67);   --sep-text: rgb(255,255,255); }\nbody[data-marca=\"club\"][data-tom=\"light\"]  { --accent: rgb(199,15,67);   --accent-border: rgb(235,153,177); --sep-bg: rgb(199,15,67);   --sep-text: rgb(255,255,255); }\nbody[data-marca=\"pro\"][data-tom=\"dark\"]    { --accent: #1F6665;          --accent-border: #104443;          --sep-bg: #1F6665;          --sep-text: #FFFFFF; }\nbody[data-marca=\"pro\"][data-tom=\"light\"]   { --accent: #1F6665;          --accent-border: #8FB8B7;          --sep-bg: #1F6665;          --sep-text: #FFFFFF; }\n\n/* ---------- TIPOGRAFIA ---------- */\n.f-display { font-family: 'Syne', sans-serif; font-weight: 600; letter-spacing: -0.01em; }\n.f-body    { font-family: 'Nunito Sans', sans-serif; }\n.f-mono    { font-family: 'DM Mono', monospace; }\n\n.kicker  { font-family: 'DM Mono', monospace; font-size: 24px; letter-spacing: 0.12em; color: var(--accent); }\n.pagenum { font-family: 'DM Mono', monospace; font-size: 24px; letter-spacing: 0.08em; color: var(--ink3); }\n\n/* ---------- ESTRUTURA DO SLIDE ---------- */\n.slide {\n  width: 1920px; height: 1080px;\n  position: relative; overflow: hidden;\n  background: var(--bg); color: var(--ink);\n  font-family: 'Nunito Sans', sans-serif;\n  box-sizing: border-box;\n}\n.frame {\n  position: absolute; inset: 0; box-sizing: border-box;\n  padding: 100px 120px 88px 120px;\n  display: flex; flex-direction: column;\n}\n.header-row { display: flex; justify-content: space-between; align-items: baseline; }\n\n/* Slide de separador usa cores próprias */\n.slide.separador { background: var(--sep-bg); color: var(--sep-text); }\n\n/* Placeholder de imagem (substituir por <img> real quando houver) */\n.img-placeholder {\n  width: 100%; height: 100%; border-radius: 16px; box-sizing: border-box;\n  border: 1px dashed var(--line35);\n  background: repeating-linear-gradient(45deg, transparent, transparent 24px, var(--hairline) 24px, var(--hairline) 48px);\n  display: flex; align-items: center; justify-content: center;\n}\n.img-placeholder span { font-family: 'DM Mono', monospace; font-size: 24px; color: var(--ink3); }\n\n/* ---------- IMPRESSÃO (Ctrl/Cmd+P → 1 página por slide) ---------- */\n@media print {\n  @page { size: 1920px 1080px; margin: 0; }\n  #hud, #contador { display: none !important; }\n  body { overflow: visible !important; background: var(--bg) !important; }\n  #stage { position: static !important; display: block !important; }\n  #stage .slide { display: block !important; transform: none !important; break-after: page; }\n}\n\n/* ---------- VISUALIZADOR (apenas para pré-visualização; não faz parte do padrão) ---------- */\nbody { margin: 0; background: rgb(14,14,16); min-height: 100vh; overflow: hidden; }\n#stage { position: fixed; inset: 0; display: flex; align-items: center; justify-content: center; }\n#stage .slide { display: none; flex-shrink: 0; transform-origin: center center; }\n#stage .slide.ativo { display: block; }\n/* ---- HUD: botão de engrenagem + drawer ---- */\n#hud {\n  position: fixed; top: 16px; right: 16px; z-index: 10;\n  font-family: 'DM Mono', monospace; font-size: 13px; color: rgb(176,175,178);\n}\n#btn-config {\n  width: 40px; height: 40px; display: flex; align-items: center; justify-content: center;\n  background: rgba(30,30,31,0.85); color: rgb(176,175,178); border: 1px solid rgb(60,60,62);\n  border-radius: 999px; font-size: 18px; cursor: pointer; opacity: 0.35; transition: opacity 0.2s, border-color 0.2s;\n}\n#btn-config:hover, body.drawer-aberto #btn-config { opacity: 1; border-color: rgb(108,107,110); }\n#drawer {\n  position: fixed; top: 0; right: 0; bottom: 0; z-index: 20;\n  width: 280px; box-sizing: border-box; padding: 24px;\n  display: flex; flex-direction: column; gap: 20px;\n  background: rgb(22,22,24); border-left: 1px solid rgb(50,50,52);\n  font-family: 'DM Mono', monospace; font-size: 13px; color: rgb(176,175,178);\n  transform: translateX(100%); transition: transform 0.25s ease;\n}\nbody.drawer-aberto #drawer { transform: translateX(0); }\n#drawer h3 { margin: 0; font-size: 13px; font-weight: 500; letter-spacing: 0.12em; color: rgb(224,223,226); }\n#drawer label { display: flex; flex-direction: column; gap: 8px; letter-spacing: 0.08em; }\n#drawer select {\n  background: rgb(30,30,31); color: rgb(224,223,226); border: 1px solid rgb(60,60,62);\n  border-radius: 8px; padding: 8px 10px; font: inherit;\n}\n#btn-tela {\n  background: rgb(30,30,31); color: rgb(224,223,226); border: 1px solid rgb(60,60,62);\n  border-radius: 8px; padding: 10px 12px; font: inherit; cursor: pointer; text-align: left;\n}\n#btn-tela:hover { border-color: rgb(108,107,110); }\n#btn-fechar {\n  position: absolute; top: 16px; right: 16px;\n  background: none; border: none; color: rgb(108,107,110); font-size: 18px; cursor: pointer; padding: 4px;\n}\n#btn-fechar:hover { color: rgb(224,223,226); }\n/* Em tela cheia, esconde tudo do visualizador */\n:fullscreen #hud, :fullscreen #contador, :fullscreen #drawer { display: none; }\n#contador {\n  position: fixed; bottom: 16px; right: 16px; z-index: 10;\n  font-family: 'DM Mono', monospace; font-size: 13px; color: rgb(108,107,110);\n}\n</style>";

export const HUD_HTML = "<div id=\"hud\">\n  <button id=\"btn-config\" title=\"Configurações\" aria-label=\"Configurações\">⚙</button>\n</div>\n<div id=\"drawer\" aria-label=\"Configurações\">\n  <button id=\"btn-fechar\" title=\"Fechar\" aria-label=\"Fechar\">×</button>\n  <h3>CONFIGURAÇÕES</h3>\n  <label>MARCA\n    <select id=\"sel-tema\" aria-label=\"Tema\">\n      <option value=\"group\">Grupo</option>\n      <option value=\"ybera\">Ybera</option>\n      <option value=\"club\">Club</option>\n      <option value=\"pro\">PRO</option>\n    </select>\n  </label>\n  <label>MODO\n    <select id=\"sel-modo\" aria-label=\"Modo\">\n      <option value=\"dark\">Dark</option>\n      <option value=\"light\">Light</option>\n    </select>\n  </label>\n  <button id=\"btn-tela\" title=\"Tela cheia (F)\">⛶ Tela cheia · F</button>\n</div>\n<div id=\"contador\"></div>";

export const LOGOS_SCRIPT = "<script id=\"logos-data\" type=\"application/json\">{\"group\":{\"dark\":\"data:image/svg+xml;base64,\",\"light\":\"data:image/svg+xml;base64,\"},\"ybera\":{\"dark\":\"data:image/svg+xml;base64,\",\"light\":\"data:image/svg+xml;base64,\"},\"club\":{\"dark\":\"data:image/svg+xml;base64,\",\"light\":\"data:image/svg+xml;base64,\"},\"pro\":{\"dark\":\"data:image/svg+xml;base64,\",\"light\":\"data:image/svg+xml;base64,\"}}</script>";

export const VIEWER_SCRIPT = "<script>\n/* ===== Visualizador (não faz parte do padrão dos slides) ===== */\nconst LOGOS = JSON.parse(document.getElementById('logos-data').textContent);\nconst slides = [...document.querySelectorAll('#stage .slide')];\nlet atual = 0;\n\nfunction aplicarTema() {\n  const t = document.body.dataset.marca;\n  const m = document.body.dataset.tom;\n  const uri = (LOGOS[t] && LOGOS[t][m]) || '';\n  document.querySelectorAll('img[data-logo]').forEach(img => { img.src = uri; });\n}\nfunction mostrar(i) {\n  atual = Math.max(0, Math.min(slides.length - 1, i));\n  slides.forEach((s, j) => s.classList.toggle('ativo', j === atual));\n  document.getElementById('contador').textContent = (atual + 1) + ' / ' + slides.length + '  ·  ← →';\n  escalar();\n}\nfunction escalar() {\n  const cheia = !!document.fullscreenElement;\n  /* Em tela cheia o slide ocupa a tela inteira; fora dela, uma folga de moldura */\n  const s = cheia\n    ? Math.min(window.innerWidth / 1920, window.innerHeight / 1080)\n    : Math.min(window.innerWidth / 1960, window.innerHeight / 1140);\n  if (!(s > 0) || !isFinite(s)) { requestAnimationFrame(escalar); return; }\n  slides[atual].style.transform = 'scale(' + s + ')';\n}\nfunction telaCheia() {\n  document.body.classList.remove('drawer-aberto');\n  if (document.fullscreenElement) document.exitFullscreen();\n  else document.documentElement.requestFullscreen();\n}\ndocument.getElementById('btn-config').addEventListener('click', () => document.body.classList.toggle('drawer-aberto'));\ndocument.getElementById('btn-fechar').addEventListener('click', () => document.body.classList.remove('drawer-aberto'));\ndocument.getElementById('btn-tela').addEventListener('click', telaCheia);\ndocument.addEventListener('fullscreenchange', escalar);\ndocument.getElementById('sel-tema').addEventListener('change', e => { document.body.dataset.marca = e.target.value; aplicarTema(); });\ndocument.getElementById('sel-modo').addEventListener('change', e => { document.body.dataset.tom = e.target.value; aplicarTema(); });\nwindow.addEventListener('resize', escalar);\nwindow.addEventListener('load', escalar);\nwindow.addEventListener('keydown', e => {\n  if (e.key === 'Escape') { document.body.classList.remove('drawer-aberto'); return; }\n  if (e.key === 'ArrowRight' || e.key === 'PageDown' || e.key === ' ') mostrar(atual + 1);\n  if (e.key === 'ArrowLeft' || e.key === 'PageUp') mostrar(atual - 1);\n  if (e.key === 'f' || e.key === 'F') telaCheia();\n});\nwindow.addEventListener('click', e => {\n  if (e.target.closest('#hud') || e.target.closest('#drawer')) return;\n  if (document.body.classList.contains('drawer-aberto')) { document.body.classList.remove('drawer-aberto'); return; }\n  mostrar(e.clientX > window.innerWidth / 2 ? atual + 1 : atual - 1);\n});\nfunction numerar() {\n  document.querySelectorAll('[data-pagina]').forEach(el => {\n    const s = el.closest('.slide');\n    const i = slides.indexOf(s);\n    if (i >= 0) el.textContent = String(i + 1).padStart(2, '0') + ' / ' + String(slides.length).padStart(2, '0');\n  });\n}\naplicarTema();\nnumerar();\nmostrar(0);\n</script>";
